// Devuelve solo pedidos vivos (no soft-deleted). Si la URL trae
// ?estado=solicitada|proforma_adjuntada|... filtramos; si trae
// ?proyecto_id=<uuid> filtramos por proyecto. Sin filtro devolvemos todos.
const raw = ($input.all() || []).map(i => i.json).filter(x => x && x.id && !x.deleted_at);
const q = ($input.first().json && $input.first().json.query) || {};
let out = raw;
if (q.estado) out = out.filter(p => p.estado === q.estado);
if (q.proyecto_id) out = out.filter(p => p.proyecto_id === q.proyecto_id);
return [{ json: { pedidos: out } }];

// Actions disponibles:
//   create                → implementador crea el pedido (estado='solicitada')
//   adjuntar_proforma     → contabilidad sube PDF (estado='proforma_adjuntada')
//   adjuntar_justificante → implementador sube pago (estado='pendiente_confirmar')
//   confirmar_pago        → contabilidad confirma (estado='lista_envio')
//   actualizar_items      → implementador edita el carrito (solo si sigue en solicitada)
//   delete                → soft-delete
//
// El body debe traer { action, pedido: { id?, ...campos } }.
// El payload se normaliza aquí para que el UPDATE/INSERT del nodo Supabase
// consuma directamente el objeto devuelto.

const b = $input.first().json.body || {};
const action = String(b.action || '').toLowerCase();
const p = b.pedido || {};
const errores = [];
const now = new Date().toISOString();

const VALID = ['create','adjuntar_proforma','adjuntar_justificante','confirmar_pago','actualizar_items','delete'];
if (!VALID.includes(action)) errores.push('action inválida: ' + action);
if (action !== 'create' && !p.id) errores.push('id obligatorio para ' + action);

let row = {};
if (action === 'create') {
  if (!p.cliente || !String(p.cliente).trim()) errores.push('cliente obligatorio');
  if (!Array.isArray(p.items) || p.items.length === 0) errores.push('items vacío');
  row = {
    proyecto_id: p.proyecto_id || null,
    cliente: String(p.cliente || '').trim(),
    implementador: p.implementador || null,
    items: p.items || [],
    estado: 'solicitada',
    notas_implementador: p.notas_implementador || null,
    solicitado_por: p.solicitado_por || null,
    solicitado_at: now
  };
} else if (action === 'adjuntar_proforma') {
  if (!p.proforma_pdf || !p.proforma_pdf.data) errores.push('proforma_pdf requerido');
  row = {
    id: p.id,
    proforma_pdf: p.proforma_pdf,
    notas_contabilidad: p.notas_contabilidad !== undefined ? p.notas_contabilidad : undefined,
    estado: 'proforma_adjuntada',
    proforma_at: now
  };
} else if (action === 'adjuntar_justificante') {
  if (!p.justificante_pdf || !p.justificante_pdf.data) errores.push('justificante_pdf requerido');
  row = {
    id: p.id,
    justificante_pdf: p.justificante_pdf,
    notas_implementador: p.notas_implementador !== undefined ? p.notas_implementador : undefined,
    estado: 'pendiente_confirmar',
    pagado_at: now
  };
} else if (action === 'confirmar_pago') {
  row = {
    id: p.id,
    notas_contabilidad: p.notas_contabilidad !== undefined ? p.notas_contabilidad : undefined,
    estado: 'lista_envio',
    confirmado_at: now
  };
} else if (action === 'actualizar_items') {
  if (!Array.isArray(p.items)) errores.push('items debe ser array');
  row = { id: p.id, items: p.items || [], notas_implementador: p.notas_implementador };
} else if (action === 'delete') {
  row = { id: p.id, deleted_at: now };
}

// Limpia undefined (el nodo Supabase con autoMapInputData mete null si le
// llega undefined, pisando el valor actual; preferimos no enviar la clave).
Object.keys(row).forEach(k => { if (row[k] === undefined) delete row[k]; });

return [{ json: { action, row, errores } }];

// Respuesta unificada — devuelve el pedido persistido + success.
const rows = ($input.all() || []).map(i => i.json).filter(x => x && x.id);
return [{ json: { success: rows.length > 0, pedido: rows[0] || null, errores: [] } }];
